        group_stats = {
            'count': data['count'],
            'avg_score': sum(data['scores']) / data['count'] if data['count'] > 0 else 0,
            'max_score': max(data['scores']) if data['count'] > 0 else 0,
            'min_score': min(data['scores']) if data['count'] > 0 else 0
        }

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                try:
                    # Evaluate function on the group's data
                    if field_name == 'count':
                        # Special case: count is already computed
                        group_stats[field_name] = data['count']
                    elif field_name == 'avg_score':
                        # Use pre-computed average
                        group_stats[field_name] = group_stats['avg_score']
                    elif field_name == 'max_score':
                        group_stats[field_name] = group_stats['max_score']
                    elif field_name == 'min_score':
                        group_stats[field_name] = group_stats['min_score']
                    else:
                        # Custom field - apply function to the group's scores
                        group_stats[field_name] = func(data['scores'])
                except Exception as e:
                    # Handle invalid functions gracefully
                    group_stats[field_name] = f"Error: {str(e)}"

        result_dict[group_value] = group_stats

    return result_dict
